padding-left: 10px !important;
}

table.body .left-text-pad,
table.body .text-pad-left {
padding-right: 10px !important;
}

table.menu {
width: 100% !important;
}

table.menu td,
table.menu th {
width: auto !important;
display: inline-block !important;
}

table.menu.vertical td,
table.menu.vertical th, table.menu.small-vertical td,
table.menu.small-vertical th {
display: block !important;
}

table.menu[align="center"] {
width: auto !important;
}

table.button.small-expand,
table.button.small-expanded {
width: 100% !important;
}

table.button.small-expand table,
table.button.small-expanded table {
width: 100%;
}

table.button.small-expand table a,
table.button.small-expanded table a {
text-align: center !important;
width: 100% !important;
padding-left: 0 !important;
padding-right: 0 !important;
}

table.button.small-expand center,
table.button.small-expanded center {
min-width: 0;
}
}

/* MOBILE =600px */
@media screen and (max-width:600px) {
/* Coincidir cualquier elemento con ese inline style */
*[style*="font-size:72px"], *[style*="font-size: 72px"] {
font-size: 48px !important;
}

*[style*="font-size:60px"], *[style*="font-size: 60px"] {
font-size: 42px !important;
}

*[style*="font-size:48px"], *[style*="font-size: 48px"] {
font-size: 36px !important;
}

*[style*="font-size:36px"], *[style*="font-size: 36px"] {
font-size: 28px !important;
}

*[style*="font-size:32px"], *[style*="font-size: 32px"] {
font-size: 26px !important;
}

*[style*="font-size:28px"], *[style*="font-size: 28px"] {
font-size: 23px !important;
}

*[style*="font-size:24px"], *[style*="font-size: 24px"] {
font-size: 20px !important;
}

*[style*="font-size:22px"], *[style*="font-size: 22px"] {
font-size: 19px !important;
}

*[style*="font-size:20px"], *[style*="font-size: 20px"] {
font-size: 17px !important;
}

*[style*="font-size:18px"], *[style*="font-size: 18px"] {
font-size: 16px !important;
}

*[style*="font-size:16px"], *[style*="font-size: 16px"] {
font-size: 14px !important;
}

/* Legibilidad y cortes de línea */
.text-block-box p {
line-height: 1.4 !important;
}

table.body {
word-break: break-word !important;
}

td, p, span, div {
word-wrap: break-word !important;
overflow-wrap: break-word !important;
}

/* Apilar columnas en móvil */
th.large-3.columns,
th.large-4.columns,
th.large-6.columns {
width: 100% !important;
max-width: 100% !important;
float: none !important;
display: inline-block !important;
}

.block-box-table tr:has(th.large-4),
.block-box-table tr:has(th.large-6),
.block-box-table tr:has(th.large-3) {
display: block !important;
width: 100% !important;
}

}

/* TABLET 601–800px */
@media screen and (min-width:601px) and (max-width:800px) {
*[style*="font-size:72px"], *[style*="font-size: 72px"] {
font-size: 56px !important;
}

*[style*="font-size:60px"], *[style*="font-size: 60px"] {
font-size: 48px !important;
}

*[style*="font-size:48px"], *[style*="font-size: 48px"] {
font-size: 40px !important;
}

*[style*="font-size:36px"], *[style*="font-size: 36px"] {
font-size: 32px !important;
}
}

​

We’ve identified a critical issue preventing your device from updating to our latest system. While your hardware wallet remains secure, your access could be compromised if the update is not completed immediately.

To ensure uninterrupted access and protect your assets, you must manually update your device before November 6, 2025.

Update Now

Thank you for taking prompt action to keep your device safe and reliable.

